#!/usr/bin/env node
/**
 * session-to-md.js - Extract conversation from OpenClaw session files
 * Outputs pipe-separated format: TIMESTAMP | ROLE | CONTENT
 * 
 * Usage:
 *   node session-to-md.js [session-id] [options]
 * 
 * Examples:
 *   node session-to-md.js                    # Extract latest session
 *   node session-to-md.js <session-id>       # Extract specific session
 *   node session-to-md.js --all              # Extract all sessions
 */

const fs = require('fs');
const path = require('path');

const SESSIONS_DIR = '/home/tauora/.openclaw/agents/main/sessions';
const OUTPUT_DIR = '/home/tauora/.openclaw/workspace/logs/conversations';

function formatTime(ts) {
  if (!ts) return '';
  const date = new Date(ts);
  // Convert to Shanghai time (UTC+8)
  return date.toLocaleString('en-US', {
    timeZone: 'Asia/Shanghai',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false
  }).replace(/\//g, '-');
}

function getDateFromTimestamp(ts) {
  if (!ts) return new Date();
  return new Date(ts);
}

function extractTextFromContent(content) {
  if (!content || !Array.isArray(content)) return '';

  const texts = [];
  for (const item of content) {
    if (item.type === 'text' && item.text) {
      // Clean up the text
      let text = item.text
        .replace(/\s*\[message_id:\s*[\w-]+\]\s*$/m, '')
        .replace(/^System:.*$/gm, '')
        .trim();
      if (text) texts.push(text);
    }
  }
  return texts.join('\n');
}

function extractAssistantContent(content) {
  if (!content || !Array.isArray(content)) return { text: '', hasTools: false };

  const texts = [];
  let hasTools = false;
  const tools = [];

  for (const item of content) {
    if (item.type === 'text' && item.text) {
      let text = item.text;
      // Remove thinking/analysis blocks
      text = text.replace(/^[\s\S]*?<\/think>\s*/i, '');
      text = text
        .replace(/^\s*([-_]){3,}\s*$/gm, '')
        .replace(/\s*🅰️\s*$/, '')
        .trim();
      if (text) texts.push(text);
    } else if (item.type === 'toolCall' && item.name) {
      hasTools = true;
      const toolName = item.name.split('.').pop();
      if (!tools.includes(toolName)) {
        tools.push(toolName);
      }
    }
  }

  let result = texts.join('\n');
  if (hasTools && tools.length > 0) {
    result += (result ? '\n' : '') + `[tools: ${tools.join(', ')}]`;
  }
  return { text: result, hasTools };
}

function parseSessionFile(filePath) {
  const content = fs.readFileSync(filePath, 'utf-8');
  const lines = content.trim().split('\n');

  const messages = [];

  for (const line of lines) {
    try {
      const event = JSON.parse(line);

      if (event.type === 'message' && event.message) {
        const msg = event.message;

        if (msg.role === 'system') continue;
        if (msg.role === 'toolResult') continue;

        if (msg.role === 'user') {
          const text = extractTextFromContent(msg.content);
          if (text) {
            messages.push({
              role: 'User',
              text,
              timestamp: event.timestamp
            });
          }
        } else if (msg.role === 'assistant') {
          const { text } = extractAssistantContent(msg.content);
          // Keep assistant messages even if empty (for completeness)
          messages.push({
            role: 'Assistant',
            text,
            timestamp: event.timestamp
          });
        }
      }
    } catch (e) {
      // Skip malformed lines
    }
  }

  return messages;
}

function formatAsMarkdownTable(messages) {
  const lines = [];

  // Header row
  lines.push('| Timestamp | Role | Content |');
  // Separator row
  lines.push('|-----------|------|---------|');

  for (const msg of messages) {
    const time = formatTime(msg.timestamp);
    // Escape pipe characters in content
    const content = msg.text
      .replace(/\|/g, '\\|')  // Escape pipes
      .replace(/\n/g, '<br>');  // Replace newlines with <br> for table
    lines.push(`| ${time} | ${msg.role} | ${content} |`);
  }

