/**
 * session-to-md.js - Extract conversation from OpenClaw session files
 * Outputs pipe-separated format: TIMESTAMP | ROLE | CONTENT
 * Combines all sessions from same day into one file
 * 
 * Usage:
 *   node session-to-md.js [options]
 * 
 * Options:
 *   --all              # Extract all sessions
 *   --today            # Extract today's sessions only (default)
 *   --date YYYY-MM-DD  # Extract specific date
 * 
 * Examples:
 *   node session-to-md.js                    # Extract today's sessions
 *   node session-to-md.js --all              # Extract all sessions
 *   node session-to-md.js --date 2026-02-04  # Extract specific date
 */

