    lines.push(`| ${time} | ${msg.role} | ${content} |`);
  }

  return lines.join('\n');
}

function getAllSessionFiles() {
  if (!fs.existsSync(SESSIONS_DIR)) {
    return [];
  }

  return fs.readdirSync(SESSIONS_DIR)
    .filter(f => f.endsWith('.jsonl'))
    .map(f => path.join(SESSIONS_DIR, f));
}

function processSessionsByDate(options = {}) {
  const sessionFiles = getAllSessionFiles();

  if (sessionFiles.length === 0) {
    console.log('No session files found');
    return;
  }

  // Group messages by date
  const messagesByDate = new Map();

  for (const filePath of sessionFiles) {
    const messages = parseSessionFile(filePath);

    for (const msg of messages) {
      const date = getShanghaiDateString(msg.timestamp);

      if (!messagesByDate.has(date)) {
        messagesByDate.set(date, []);
      }
      messagesByDate.get(date).push(msg);
    }
